using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Warehouse.Tests;

[TestClass]
public sealed class InventoryTrackerTests
{
    private InventoryTracker _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new InventoryTracker();

    #region GetStockLevel

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _sut.GetStockLevel("SKU-999"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GetStockLevel_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.GetStockLevel(sku!));
    }

    #endregion

    #region AddStock

    [TestMethod]
    [DataRow(1, DisplayName = "Add 1 unit")]
    [DataRow(100, DisplayName = "Add 100 units")]
    public void AddStock_ValidQuantity_IncreasesStockLevel(int quantity)
    {
        _sut.AddStock("WIDGET-A", quantity);

        Assert.AreEqual(quantity, _sut.GetStockLevel("WIDGET-A"));
    }

    [TestMethod]
    public void AddStock_CalledMultipleTimes_Accumulates()
    {
        _sut.AddStock("WIDGET-A", 10);
        _sut.AddStock("WIDGET-A", 5);

        Assert.AreEqual(15, _sut.GetStockLevel("WIDGET-A"));
    }

    [TestMethod]
    public void AddStock_IsCaseInsensitive()
    {
        _sut.AddStock("widget-a", 3);
        _sut.AddStock("WIDGET-A", 7);

        Assert.AreEqual(10, _sut.GetStockLevel("Widget-A"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddStock_NonPositiveQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddStock("WIDGET-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void AddStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddStock(sku!, 5));
    }

    #endregion

    #region RemoveStock

    [TestMethod]
    public void RemoveStock_SufficientStock_DecreasesLevel()
    {
        _sut.AddStock("BOLT", 20);

        _sut.RemoveStock("BOLT", 8);

        Assert.AreEqual(12, _sut.GetStockLevel("BOLT"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_LeavesZero()
    {
        _sut.AddStock("BOLT", 5);

        _sut.RemoveStock("BOLT", 5);

        Assert.AreEqual(0, _sut.GetStockLevel("BOLT"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_ThrowsInvalidOperation()
    {
        _sut.AddStock("BOLT", 3);

        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveStock("BOLT", 10));

        StringAssert.Contains(ex.Message, "Insufficient stock");
    }

    [TestMethod]
    public void RemoveStock_UnknownSku_ThrowsInvalidOperation()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveStock("UNKNOWN", 1));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void RemoveStock_NonPositiveQuantity_Throws(int quantity)
    {
        _sut.AddStock("BOLT", 10);

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.RemoveStock("BOLT", quantity));
    }

    #endregion

    #region NeedsReorder

    [TestMethod]
    public void NeedsReorder_NoThresholdSet_ReturnsFalse()
    {
        _sut.AddStock("GEAR", 0);

        Assert.IsFalse(_sut.NeedsReorder("GEAR"));
    }

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _sut.SetReorderThreshold("GEAR", 10);
        _sut.AddStock("GEAR", 5);

        Assert.IsTrue(_sut.NeedsReorder("GEAR"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        _sut.SetReorderThreshold("GEAR", 10);
        _sut.AddStock("GEAR", 10);

        Assert.IsTrue(_sut.NeedsReorder("GEAR"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _sut.SetReorderThreshold("GEAR", 10);
        _sut.AddStock("GEAR", 50);

        Assert.IsFalse(_sut.NeedsReorder("GEAR"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void NeedsReorder_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.NeedsReorder(sku!));
    }

    #endregion

    #region SetReorderThreshold

    [TestMethod]
    public void SetReorderThreshold_ZeroThreshold_IsValid()
    {
        _sut.SetReorderThreshold("PART-X", 0);
        _sut.AddStock("PART-X", 1);

        Assert.IsFalse(_sut.NeedsReorder("PART-X"));
    }

    [TestMethod]
    public void SetReorderThreshold_NegativeThreshold_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.SetReorderThreshold("PART-X", -1));
    }

    [TestMethod]
    public void SetReorderThreshold_UpdatesExistingThreshold()
    {
        _sut.SetReorderThreshold("PART-X", 100);
        _sut.AddStock("PART-X", 50);
        Assert.IsTrue(_sut.NeedsReorder("PART-X"));

        _sut.SetReorderThreshold("PART-X", 5);
        Assert.IsFalse(_sut.NeedsReorder("PART-X"));
    }

    #endregion

    #region GetReorderAlerts

    [TestMethod]
    public void GetReorderAlerts_NoThresholds_ReturnsEmpty()
    {
        var alerts = _sut.GetReorderAlerts();

        Assert.AreEqual(0, alerts.Count);
    }

    [TestMethod]
    public void GetReorderAlerts_MultipleSkusBelowThreshold_ReturnsAll()
    {
        _sut.SetReorderThreshold("A", 10);
        _sut.SetReorderThreshold("B", 5);
        _sut.SetReorderThreshold("C", 20);
        _sut.AddStock("A", 3);
        _sut.AddStock("B", 100);
        _sut.AddStock("C", 2);

        var alerts = _sut.GetReorderAlerts();

        CollectionAssert.Contains(alerts.ToList(), "A");
        CollectionAssert.Contains(alerts.ToList(), "C");
        CollectionAssert.DoesNotContain(alerts.ToList(), "B");
        Assert.AreEqual(2, alerts.Count);
    }

    #endregion

    #region TransferTo (Warehouse Transfers)

    [TestMethod]
    public void TransferTo_ValidTransfer_MovesStockBetweenTrackers()
    {
        var destination = new InventoryTracker();
        _sut.AddStock("MOTOR", 50);

        _sut.TransferTo(destination, "MOTOR", 20);

        Assert.AreEqual(30, _sut.GetStockLevel("MOTOR"));
        Assert.AreEqual(20, destination.GetStockLevel("MOTOR"));
    }

    [TestMethod]
    public void TransferTo_EntireStock_SourceBecomesZero()
    {
        var destination = new InventoryTracker();
        _sut.AddStock("MOTOR", 10);

        _sut.TransferTo(destination, "MOTOR", 10);

        Assert.AreEqual(0, _sut.GetStockLevel("MOTOR"));
        Assert.AreEqual(10, destination.GetStockLevel("MOTOR"));
    }

    [TestMethod]
    public void TransferTo_InsufficientStock_ThrowsAndDoesNotModifyDestination()
    {
        var destination = new InventoryTracker();
        _sut.AddStock("MOTOR", 5);
        destination.AddStock("MOTOR", 10);

        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.TransferTo(destination, "MOTOR", 50));

        // Neither tracker should be modified on failure
        Assert.AreEqual(5, _sut.GetStockLevel("MOTOR"));
        Assert.AreEqual(10, destination.GetStockLevel("MOTOR"));
    }

    [TestMethod]
    public void TransferTo_NullDestination_Throws()
    {
        _sut.AddStock("MOTOR", 10);

        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.TransferTo(null!, "MOTOR", 5));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void TransferTo_NonPositiveQuantity_Throws(int quantity)
    {
        var destination = new InventoryTracker();
        _sut.AddStock("MOTOR", 10);

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.TransferTo(destination, "MOTOR", quantity));
