1. using Microsoft.VisualStudio.TestTools.UnitTesting;
2. 
3. namespace Warehouse.Tests;
4. 
5. [TestClass]
6. public sealed class InventoryTrackerTests
7. {
8.     private InventoryTracker _sut = null!;
9. 
10.     [TestInitialize]
11.     public void Setup() => _sut = new InventoryTracker();
12. 
13.     #region GetStockLevel
14. 
15.     [TestMethod]
16.     public void GetStockLevel_UnknownSku_ReturnsZero()
17.     {
18.         Assert.AreEqual(0, _sut.GetStockLevel("SKU-999"));
19.     }
20. 
21.     [TestMethod]
22.     public void GetStockLevel_NullSku_ThrowsArgumentNull()
23.     {
24.         Assert.ThrowsExactly<ArgumentNullException>(() => _sut.GetStockLevel(null!));
25.     }
26. 
27.     [TestMethod]
28.     [DataRow("")]
29.     [DataRow("   ")]
30.     public void GetStockLevel_EmptyOrWhitespaceSku_Throws(string sku)
31.     {
32.         Assert.ThrowsExactly<ArgumentException>(() => _sut.GetStockLevel(sku));
33.     }
34. 
35.     #endregion
36. 
37.     #region AddStock
38. 
39.     [TestMethod]
40.     [DataRow(1, DisplayName = "Add 1 unit")]
41.     [DataRow(100, DisplayName = "Add 100 units")]
42.     public void AddStock_ValidQuantity_IncreasesStockLevel(int quantity)
43.     {
44.         _sut.AddStock("WIDGET-A", quantity);
45. 
46.         Assert.AreEqual(quantity, _sut.GetStockLevel("WIDGET-A"));
47.     }
48. 
49.     [TestMethod]
50.     public void AddStock_CalledMultipleTimes_Accumulates()
51.     {
52.         _sut.AddStock("WIDGET-A", 10);
53.         _sut.AddStock("WIDGET-A", 5);
54. 
55.         Assert.AreEqual(15, _sut.GetStockLevel("WIDGET-A"));
56.     }
57. 
58.     [TestMethod]
59.     public void AddStock_IsCaseInsensitive()
60.     {
61.         _sut.AddStock("widget-a", 3);
62.         _sut.AddStock("WIDGET-A", 7);
63. 
64.         Assert.AreEqual(10, _sut.GetStockLevel("Widget-A"));
65.     }
66. 
67.     [TestMethod]
68.     [DataRow(0)]
69.     [DataRow(-1)]
70.     public void AddStock_NonPositiveQuantity_Throws(int quantity)
71.     {
72.         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
73.             () => _sut.AddStock("WIDGET-A", quantity));
74.     }
75. 
76.     [TestMethod]
77.     public void AddStock_NullSku_ThrowsArgumentNull()
78.     {
79.         Assert.ThrowsExactly<ArgumentNullException>(() => _sut.AddStock(null!, 5));
80.     }
81. 
82.     [TestMethod]
83.     [DataRow("")]
84.     [DataRow("  ")]
85.     public void AddStock_EmptyOrWhitespaceSku_Throws(string sku)
86.     {
87.         Assert.ThrowsExactly<ArgumentException>(() => _sut.AddStock(sku, 5));
88.     }
89. 
90.     #endregion
91. 
92.     #region RemoveStock
93. 
94.     [TestMethod]
95.     public void RemoveStock_SufficientStock_DecreasesLevel()
96.     {
97.         _sut.AddStock("BOLT", 20);
98. 
99.         _sut.RemoveStock("BOLT", 8);
100. 
101.         Assert.AreEqual(12, _sut.GetStockLevel("BOLT"));
102.     }
103. 
104.     [TestMethod]
105.     public void RemoveStock_EntireStock_LeavesZero()
106.     {
107.         _sut.AddStock("BOLT", 5);
108. 
109.         _sut.RemoveStock("BOLT", 5);
110. 
111.         Assert.AreEqual(0, _sut.GetStockLevel("BOLT"));
112.     }
113. 
114.     [TestMethod]
115.     public void RemoveStock_InsufficientStock_ThrowsInvalidOperation()
116.     {
117.         _sut.AddStock("BOLT", 3);
118. 
119.         var ex = Assert.ThrowsExactly<InvalidOperationException>(
120.             () => _sut.RemoveStock("BOLT", 10));
121. 
122.         StringAssert.Contains(ex.Message, "Insufficient stock");
123.     }
124. 
125.     [TestMethod]
126.     public void RemoveStock_UnknownSku_ThrowsInvalidOperation()
127.     {
128.         Assert.ThrowsExactly<InvalidOperationException>(
129.             () => _sut.RemoveStock("UNKNOWN", 1));
130.     }
131. 
132.     [TestMethod]
133.     [DataRow(0)]
134.     [DataRow(-5)]
135.     public void RemoveStock_NonPositiveQuantity_Throws(int quantity)
136.     {
137.         _sut.AddStock("BOLT", 10);
138. 
139.         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
140.             () => _sut.RemoveStock("BOLT", quantity));
141.     }
142. 
143.     #endregion
144. 
145.     #region NeedsReorder
146. 
147.     [TestMethod]
148.     public void NeedsReorder_NoThresholdSet_ReturnsFalse()
149.     {
150.         Assert.IsFalse(_sut.NeedsReorder("GEAR"));
151.     }
152. 
153.     [TestMethod]
154.     public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
155.     {
156.         _sut.SetReorderThreshold("GEAR", 10);
157.         _sut.AddStock("GEAR", 5);
158. 
159.         Assert.IsTrue(_sut.NeedsReorder("GEAR"));
160.     }
161. 
162.     [TestMethod]
163.     public void NeedsReorder_StockAtThreshold_ReturnsTrue()
164.     {
165.         _sut.SetReorderThreshold("GEAR", 10);
166.         _sut.AddStock("GEAR", 10);
167. 
168.         Assert.IsTrue(_sut.NeedsReorder("GEAR"));
169.     }
170. 
171.     [TestMethod]
172.     public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
173.     {
174.         _sut.SetReorderThreshold("GEAR", 10);
175.         _sut.AddStock("GEAR", 50);
176. 
177.         Assert.IsFalse(_sut.NeedsReorder("GEAR"));
178.     }
179. 
180.     [TestMethod]
181.     public void NeedsReorder_NullSku_ThrowsArgumentNull()
182.     {
183.         Assert.ThrowsExactly<ArgumentNullException>(() => _sut.NeedsReorder(null!));
184.     }
185. 
186.     [TestMethod]
187.     public void NeedsReorder_EmptySku_Throws()
188.     {
189.         Assert.ThrowsExactly<ArgumentException>(() => _sut.NeedsReorder(""));
190.     }
191. 
192.     #endregion
193. 
194.     #region SetReorderThreshold
195. 
196.     [TestMethod]
197.     public void SetReorderThreshold_ZeroThreshold_IsValid()
198.     {
199.         _sut.SetReorderThreshold("PART-X", 0);
200.         _sut.AddStock("PART-X", 1);
201. 
202.         Assert.IsFalse(_sut.NeedsReorder("PART-X"));
203.     }
204. 
205.     [TestMethod]
206.     public void SetReorderThreshold_NegativeThreshold_Throws()
207.     {
208.         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
209.             () => _sut.SetReorderThreshold("PART-X", -1));
210.     }
211. 
212.     [TestMethod]
213.     public void SetReorderThreshold_UpdatesExistingThreshold()
214.     {
215.         _sut.SetReorderThreshold("PART-X", 100);
216.         _sut.AddStock("PART-X", 50);
217.         Assert.IsTrue(_sut.NeedsReorder("PART-X"));
218. 
219.         _sut.SetReorderThreshold("PART-X", 5);
220.         Assert.IsFalse(_sut.NeedsReorder("PART-X"));
221.     }
222. 
223.     #endregion
224. 
225.     #region GetReorderAlerts
226. 
227.     [TestMethod]
228.     public void GetReorderAlerts_NoThresholds_ReturnsEmpty()
229.     {
230.         var alerts = _sut.GetReorderAlerts();
231. 
232.         Assert.AreEqual(0, alerts.Count);
233.     }
234. 
235.     [TestMethod]
236.     public void GetReorderAlerts_MultipleSkusBelowThreshold_ReturnsAll()
237.     {
238.         _sut.SetReorderThreshold("A", 10);
239.         _sut.SetReorderThreshold("B", 5);
240.         _sut.SetReorderThreshold("C", 20);
241.         _sut.AddStock("A", 3);
242.         _sut.AddStock("B", 100);
243.         _sut.AddStock("C", 2);
244. 
245.         var alerts = _sut.GetReorderAlerts();
246. 
247.         CollectionAssert.Contains(alerts.ToList(), "A");
248.         CollectionAssert.Contains(alerts.ToList(), "C");
249.         CollectionAssert.DoesNotContain(alerts.ToList(), "B");
250.         Assert.AreEqual(2, alerts.Count);
251.     }
252. 
253.     #endregion
254. 
255.     #region TransferTo (Warehouse Transfers)
256. 
257.     [TestMethod]
258.     public void TransferTo_ValidTransfer_MovesStockBetweenTrackers()
259.     {
260.         var destination = new InventoryTracker();
